    clearQueue();
    sessionRef.current.interrupt();
  }, [clearQueue]);

  return {
    isReady,
    isSpeaking,
    startSession,
    stopSession,
    speak,
    interrupt,
    clearQueue,
    avatarRef,
  };
}

