    10→const API_URL = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000";
    11→
    12→export interface UseLiveAvatarReturn {
    13→  isReady: boolean;
    14→  isSpeaking: boolean;
    15→  startSession: () => Promise<void>;
    16→  stopSession: () => Promise<void>;
    17→  speak: (text: string) => void;
    18→  interrupt: () => void;
    19→  clearQueue: () => void;
    20→  avatarRef: React.RefObject<HTMLVideoElement | null>;
    21→}
    22→
    23→async function fetchSessionToken(): Promise<string> {
    24→  const res = await fetch(`${API_URL}/api/heygen/token`, {
    25→    method: "POST",
    26→    headers: { "Content-Type": "application/json" },
    27→    body: JSON.stringify({ is_sandbox: true }),
    28→  });
    29→  if (!res.ok) throw new Error(`Failed to fetch LiveAvatar token: ${res.status}`);
    30→  const data = await res.json();
    31→  return data.session_token;
    32→}
    33→
    34→export function useLiveAvatar(): UseLiveAvatarReturn {
    35→  const [isReady, setIsReady] = useState(false);
    36→  const [isSpeaking, setIsSpeaking] = useState(false);
    37→  const avatarRef = useRef<HTMLVideoElement | null>(null);
    38→  const sessionRef = useRef<LiveAvatarSession | null>(null);
    39→
    40→  // Speech queue — process one sentence at a time to prevent overlapping speech
    41→  const speechQueueRef = useRef<string[]>([]);
    42→  const isProcessingQueueRef = useRef(false);
    43→
    44→  const processQueue = useCallback(() => {
    45→    if (isProcessingQueueRef.current || !sessionRef.current) return;
    46→    const next = speechQueueRef.current.shift();
    47→    if (!next) {
    48→      setIsSpeaking(false);
    49→      return;
    50→    }
    51→    isProcessingQueueRef.current = true;
    52→    setIsSpeaking(true);
    53→    try {
    54→      sessionRef.current.repeat(next);
    55→    } catch (err) {
    56→      console.error("[LiveAvatar] repeat() failed:", err);
    57→      isProcessingQueueRef.current = false;
    58→      processQueue();
    59→    }
    60→    // isProcessingQueueRef is reset by AVATAR_SPEAK_ENDED handler
    61→  }, []);
    62→
    63→  const clearQueue = useCallback(() => {
    64→    speechQueueRef.current = [];
    65→    isProcessingQueueRef.current = false;
    66→  }, []);
    67→
    68→  // Cleanup on unmount
    69→  useEffect(() => {
    70→    return () => {
    71→      clearQueue();
    72→      sessionRef.current?.stop().catch(() => {});
    73→      sessionRef.current = null;
    74→    };
    75→  }, [clearQueue]);
    76→
    77→  const startSession = useCallback(async () => {
    78→    if (sessionRef.current) return;
    79→
    80→    const token = await fetchSessionToken();
    81→    const session = new LiveAvatarSession(token);
    82→    sessionRef.current = session;
    83→
    84→    session.on(SessionEvent.SESSION_STREAM_READY, () => {
    85→      if (avatarRef.current) {
    86→        session.attach(avatarRef.current);
    87→      }
    88→      setIsReady(true);
    89→    });
    90→
    91→    session.on(AgentEventsEnum.AVATAR_SPEAK_STARTED, () => {
    92→      setIsSpeaking(true);
    93→    });
    94→
    95→    session.on(AgentEventsEnum.AVATAR_SPEAK_ENDED, () => {
    96→      isProcessingQueueRef.current = false;
    97→      processQueue();
    98→    });
    99→
   100→    session.on(SessionEvent.SESSION_DISCONNECTED, () => {
   101→      setIsReady(false);
   102→      setIsSpeaking(false);
   103→      clearQueue();
   104→      sessionRef.current = null;
   105→    });
   106→
   107→    await session.start();
   108→  }, [processQueue, clearQueue]);
   109→
   110→  const stopSession = useCallback(async () => {
   111→    if (!sessionRef.current) return;
   112→    clearQueue();
   113→    await sessionRef.current.stop();
   114→    sessionRef.current = null;
   115→    setIsReady(false);
   116→    setIsSpeaking(false);
   117→  }, [clearQueue]);
   118→
   119→  const speak = useCallback(
   120→    (text: string) => {
   121→      if (!text.trim()) return;
   122→      speechQueueRef.current.push(text);
   123→      setIsSpeaking(true);
   124→      processQueue();
   125→    },
   126→    [processQueue],
   127→  );
   128→
   129→  const interrupt = useCallback(() => {
   130→    if (!sessionRef.current) return;
   131→    clearQueue();
   132→    sessionRef.current.interrupt();
   133→  }, [clearQueue]);
   134→
   135→  return {
   136→    isReady,
   137→    isSpeaking,
   138→    startSession,
   139→    stopSession,
   140→    speak,
   141→    interrupt,
   142→    clearQueue,
   143→    avatarRef,
   144→  };
   145→}
