     1→"use client";
     2→
     3→import { Suspense } from "react";
     4→import { useCallback, useEffect, useMemo, useRef, useState } from "react";
     5→import { useSearchParams } from "next/navigation";
     6→import { useCamera } from "@/hooks/useCamera";
     7→import { useGestureRecognizer } from "@/hooks/useGestureRecognizer";
     8→import { useLiveAvatar } from "@/hooks/useLiveAvatar";
     9→import { useDeepgramSTT } from "@/hooks/useDeepgramSTT";
    10→import { GestureIndicator } from "@/components/mirror/GestureIndicator";
    11→import AvatarPiP from "@/components/mirror/AvatarPiP";
    12→import VoiceIndicator from "@/components/mirror/VoiceIndicator";
    13→import ProductCarousel, {
    14→  type ProductCard,
    15→} from "@/components/mirror/ProductCarousel";
    16→import { SentenceBuffer } from "@/lib/sentence-buffer";
    17→import { socket } from "@/lib/socket";
    18→import type { DetectedGesture, GestureType } from "@/types/gestures";
    19→
    20→export default function MirrorPageWrapper() {
    21→  return (
    22→    <Suspense fallback={null}>
    23→      <MirrorPage />
    24→    </Suspense>
    25→  );
    26→}
    27→
    28→function MirrorPage() {
    29→  const searchParams = useSearchParams();
    30→  const userId = searchParams.get("user_id");
    31→
    32→  // Camera + gesture recognition
    33→  const { videoRef, isReady: isCameraReady, error: cameraError } = useCamera();
    34→  const [lastGesture, setLastGesture] = useState<GestureType | null>(null);
    35→  const gestureKeyRef = useRef(0);
    36→  const [gestureKey, setGestureKey] = useState(0);
    37→
    38→  // Session state
    39→  const [sessionActive, setSessionActive] = useState(false);
    40→  const [isStarting, setIsStarting] = useState(false);
    41→  const [products, setProducts] = useState<ProductCard[]>([]);
    42→
    43→  // Avatar + voice
    44→  const avatar = useLiveAvatar();
    45→  const stt = useDeepgramSTT();
    46→
    47→  // Queue transcripts while avatar is speaking, send when quiet
    48→  const pendingTranscriptRef = useRef<string | null>(null);
    49→
    50→  // Sentence buffer: accumulates streamed speech chunks → fires complete sentences to avatar
    51→  const sentenceBuffer = useMemo(
    52→    () =>
    53→      new SentenceBuffer((sentence) => {
    54→        avatar.speak(sentence);
    55→      }),
    56→    // avatar.speak is stable (useCallback), safe to depend on
    57→    // eslint-disable-next-line react-hooks/exhaustive-deps
    58→    [avatar.speak],
    59→  );
    60→
    61→  // Connect socket and join user room
    62→  useEffect(() => {
    63→    socket.connect();
    64→
    65→    if (userId) {
    66→      socket.emit("join_room", { user_id: userId });
    67→    }
    68→
    69→    return () => {
    70→      socket.disconnect();
    71→    };
    72→  }, [userId]);
    73→
    74→  // Listen for session_active from backend
    75→  useEffect(() => {
    76→    const handleSessionActive = () => {
    77→      setSessionActive(true);
    78→      setIsStarting(false);
    79→      avatar.startSession();
    80→      stt.startListening();
    81→    };
    82→
    83→    socket.on("session_active", handleSessionActive);
    84→    return () => {
    85→      socket.off("session_active", handleSessionActive);
    86→    };
    87→    // avatar.startSession and stt.startListening are stable refs
    88→    // eslint-disable-next-line react-hooks/exhaustive-deps
    89→  }, []);
    90→
    91→  // Listen for mira_speech events (streamed text from AI)
    92→  useEffect(() => {
    93→    const handleSpeech = (data: { text?: string; is_chunk?: boolean }) => {
    94→      // Fallback session detection: if we get speech before session_active
    95→      if (!sessionActive && !isStarting) {
    96→        setSessionActive(true);
    97→        setIsStarting(false);
    98→        avatar.startSession();
    99→        stt.startListening();
   100→      }
   101→
   102→      if (data.text) {
   103→        if (data.is_chunk === false) {
   104→          // End of message — flush remaining buffer
   105→          sentenceBuffer.feed(data.text);
   106→          sentenceBuffer.flush();
   107→        } else {
   108→          sentenceBuffer.feed(data.text);
   109→        }
   110→      }
   111→    };
   112→
   113→    socket.on("mira_speech", handleSpeech);
   114→    return () => {
   115→      socket.off("mira_speech", handleSpeech);
   116→    };
   117→    // eslint-disable-next-line react-hooks/exhaustive-deps
   118→  }, [sessionActive, isStarting, sentenceBuffer]);
   119→
   120→  // Listen for tool_result events (product recommendations)
   121→  useEffect(() => {
   122→    const handleToolResult = (data: { tool?: string; items?: ProductCard[] }) => {
   123→      if (data.tool === "present_items" && data.items) {
   124→        setProducts(data.items);
   125→      }
   126→    };
   127→
   128→    socket.on("tool_result", handleToolResult);
   129→    return () => {
   130→      socket.off("tool_result", handleToolResult);
   131→    };
   132→  }, []);
   133→
   134→  // Listen for session_ended
   135→  useEffect(() => {
   136→    const handleSessionEnded = () => {
   137→      avatar.stopSession();
   138→      stt.stopListening();
   139→      setSessionActive(false);
   140→      setProducts([]);
   141→    };
   142→
   143→    socket.on("session_ended", handleSessionEnded);
   144→    return () => {
   145→      socket.off("session_ended", handleSessionEnded);
   146→    };
   147→    // eslint-disable-next-line react-hooks/exhaustive-deps
   148→  }, []);
   149→
   150→  // Send transcripts to backend when avatar stops speaking
   151→  useEffect(() => {
   152→    if (!avatar.isSpeaking && pendingTranscriptRef.current && userId) {
   153→      socket.emit("mirror_event", {
   154→        user_id: userId,
   155→        event: { type: "voice", transcript: pendingTranscriptRef.current },
   156→      });
   157→      pendingTranscriptRef.current = null;
   158→    }
   159→  }, [avatar.isSpeaking, userId]);
   160→
   161→  // Forward final STT transcripts
   162→  useEffect(() => {
   163→    if (!stt.transcript || !userId) return;
   164→
   165→    if (avatar.isSpeaking) {
   166→      // Queue transcript until avatar is done speaking to avoid interruption
   167→      pendingTranscriptRef.current = stt.transcript;
   168→    } else {
   169→      socket.emit("mirror_event", {
   170→        user_id: userId,
   171→        event: { type: "voice", transcript: stt.transcript },
   172→      });
   173→    }
   174→    // eslint-disable-next-line react-hooks/exhaustive-deps
   175→  }, [stt.transcript, userId]);
   176→
   177→  // Listen for snapshot requests from the backend
   178→  useEffect(() => {
   179→    const handleSnapshotRequest = () => {
   180→      const video = videoRef.current;
   181→      if (!video || video.readyState < video.HAVE_CURRENT_DATA) return;
   182→
   183→      const canvas = document.createElement("canvas");
   184→      canvas.width = video.videoWidth;
   185→      canvas.height = video.videoHeight;
   186→      const ctx = canvas.getContext("2d");
   187→      if (!ctx) return;
   188→
   189→      ctx.drawImage(video, 0, 0);
   190→      const dataUrl = canvas.toDataURL("image/jpeg", 0.7);
   191→      const base64 = dataUrl.split(",")[1];
   192→
   193→      socket.emit("mirror_event", {
   194→        type: "snapshot",
   195→        image_base64: base64,
   196→        user_id: userId,
   197→      });
   198→    };
   199→
   200→    socket.on("request_snapshot", handleSnapshotRequest);
   201→    return () => {
   202→      socket.off("request_snapshot", handleSnapshotRequest);
   203→    };
   204→  }, [videoRef, userId]);
   205→
   206→  // Gesture handler
   207→  const handleGesture = useCallback(
   208→    (gesture: DetectedGesture) => {
   209→      console.log("[Mirror] Gesture detected:", gesture.type, gesture.confidence);
   210→
   211→      setLastGesture(gesture.type);
   212→      gestureKeyRef.current += 1;
   213→      setGestureKey(gestureKeyRef.current);
   214→
   215→      // Forward to carousel if it exists
   216→      const carouselGesture = (
   217→        window as unknown as Record<string, unknown>
   218→      ).__carouselGesture as ((g: GestureType) => void) | undefined;
   219→      if (carouselGesture) {
   220→        carouselGesture(gesture.type);
   221→      }
   222→
   223→      socket.emit("mirror_event", {
   224→        user_id: userId,
   225→        event: {
   226→          type: "gesture",
   227→          gesture: gesture.type,
   228→          confidence: gesture.confidence,
   229→          timestamp: gesture.timestamp,
   230→        },
   231→      });
   232→    },
   233→    [userId],
   234→  );
   235→
   236→  const { isLoading: isModelLoading, error: modelError } =
   237→    useGestureRecognizer({
   238→      videoRef,
   239→      isVideoReady: isCameraReady,
   240→      onGesture: handleGesture,
   241→    });
   242→
   243→  const handleProductGesture = useCallback(
   244→    (gesture: GestureType, item: ProductCard) => {
   245→      socket.emit("mirror_event", {
   246→        user_id: userId,
   247→        event: {
   248→          type: "product_gesture",
   249→          gesture,
   250→          product_id: item.product_id,
   251→          title: item.title,
   252→        },
   253→      });
   254→    },
   255→    [userId],
   256→  );
   257→
   258→  const handleStartSession = useCallback(() => {
   259→    if (!userId || isStarting || sessionActive) return;
   260→    setIsStarting(true);
   261→    socket.emit("start_session", { user_id: userId });
   262→  }, [userId, isStarting, sessionActive]);
   263→
   264→  return (
   265→    <main
   266→      style={{
   267→        position: "relative",
   268→        width: "100vw",
   269→        height: "100vh",
   270→        background: "#000",
   271→        overflow: "hidden",
   272→      }}
   273→    >
   274→      {/* Webcam feed (mirrored) */}
   275→      <video
   276→        ref={videoRef}
   277→        autoPlay
   278→        playsInline
   279→        muted
   280→        style={{
   281→          position: "absolute",
   282→          top: 0,
   283→          left: 0,
   284→          width: "100%",
   285→          height: "100%",
   286→          objectFit: "cover",
   287→          transform: "scaleX(-1)",
   288→        }}
   289→      />
   290→
   291→      {/* Start Session button (pre-session overlay) */}
   292→      {!sessionActive && !isStarting && (
   293→        <div
   294→          style={{
   295→            position: "absolute",
   296→            top: "50%",
   297→            left: "50%",
   298→            transform: "translate(-50%, -50%)",
   299→            zIndex: 20,
   300→          }}
   301→        >
