    81→    };
    82→
    83→    socket.on("session_active", handleSessionActive);
    84→    return () => {
    85→      socket.off("session_active", handleSessionActive);
    86→    };
    87→    // avatar.startSession and stt.startListening are stable refs
    88→    // eslint-disable-next-line react-hooks/exhaustive-deps
    89→  }, []);
    90→
    91→  // Listen for mira_speech events (streamed text from AI)
    92→  useEffect(() => {
    93→    const handleSpeech = (data: { text?: string; is_chunk?: boolean }) => {
    94→      // Fallback session detection: if we get speech before session_active
