   170→        user_id: userId,
   171→        event: { type: "voice", transcript: stt.transcript },
   172→      });
   173→    }
   174→    // eslint-disable-next-line react-hooks/exhaustive-deps
   175→  }, [stt.transcript, userId]);
   176→
   177→  // Listen for snapshot requests from the backend
   178→  useEffect(() => {
   179→    const handleSnapshotRequest = () => {
   180→      const video = videoRef.current;
   181→      if (!video || video.readyState < video.HAVE_CURRENT_DATA) return;
   182→
   183→      const canvas = document.createElement("canvas");
   184→      canvas.width = video.videoWidth;
   185→      canvas.height = video.videoHeight;
   186→      const ctx = canvas.getContext("2d");
   187→      if (!ctx) return;
   188→
   189→      ctx.drawImage(video, 0, 0);
   190→      const dataUrl = canvas.toDataURL("image/jpeg", 0.7);
   191→      const base64 = dataUrl.split(",")[1];
