   193→      socket.emit("mirror_event", {
   194→        type: "snapshot",
   195→        image_base64: base64,
   196→        user_id: userId,
   197→      });
   198→    };
   199→
   200→    socket.on("request_snapshot", handleSnapshotRequest);
   201→    return () => {
   202→      socket.off("request_snapshot", handleSnapshotRequest);
   203→    };
   204→  }, [videoRef, userId]);
   205→
   206→  // Gesture handler
   207→  const handleGesture = useCallback(
   208→    (gesture: DetectedGesture) => {
   209→      console.log("[Mirror] Gesture detected:", gesture.type, gesture.confidence);
