    10→const API_URL = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000";
    11→
    12→export interface UseLiveAvatarReturn {
    13→  isReady: boolean;
    14→  isSpeaking: boolean;
    15→  startSession: () => Promise<void>;
    16→  stopSession: () => Promise<void>;
    17→  speak: (text: string) => void;
    18→  interrupt: () => void;
    19→  clearQueue: () => void;
    20→  avatarRef: React.RefObject<HTMLVideoElement | null>;
    21→}
    22→
    23→async function fetchSessionToken(): Promise<string> {
    24→  const res = await fetch(`${API_URL}/api/heygen/token`, {
    25→    method: "POST",
    26→    headers: { "Content-Type": "application/json" },
    27→    body: JSON.stringify({ is_sandbox: true }),
    28→  });
    29→  if (!res.ok) throw new Error(`Failed to fetch LiveAvatar token: ${res.status}`);
    30→  const data = await res.json();
    31→  return data.session_token;
    32→}
    33→
    34→export function useLiveAvatar(): UseLiveAvatarReturn {
    35→  const [isReady, setIsReady] = useState(false);
    36→  const [isSpeaking, setIsSpeaking] = useState(false);
    37→  const avatarRef = useRef<HTMLVideoElement | null>(null);
    38→  const sessionRef = useRef<LiveAvatarSession | null>(null);
    39→  const isReadyRef = useRef(false);
    40→
    41→  // Speech queue — process one sentence at a time to prevent overlapping speech
    42→  const speechQueueRef = useRef<string[]>([]);
    43→  const isProcessingQueueRef = useRef(false);
    44→
    45→  const processQueue = useCallback(() => {
    46→    // Don't attempt repeat() until the session is actually connected
    47→    if (isProcessingQueueRef.current || !sessionRef.current || !isReadyRef.current) return;
    48→    const next = speechQueueRef.current.shift();
    49→    if (!next) {
    50→      setIsSpeaking(false);
    51→      return;
    52→    }
    53→    isProcessingQueueRef.current = true;
    54→    setIsSpeaking(true);
    55→    console.log("[LiveAvatar] repeat():", next.slice(0, 60));
    56→    try {
    57→      sessionRef.current.repeat(next);
    58→    } catch (err) {
    59→      console.error("[LiveAvatar] repeat() failed:", err);
    60→      isProcessingQueueRef.current = false;
    61→      // Don't recursively retry — wait for next speak() or AVATAR_SPEAK_ENDED
    62→    }
    63→  }, []);
    64→
    65→  const clearQueue = useCallback(() => {
    66→    speechQueueRef.current = [];
    67→    isProcessingQueueRef.current = false;
    68→  }, []);
    69→
    70→  // Cleanup on unmount
    71→  useEffect(() => {
    72→    return () => {
    73→      clearQueue();
    74→      sessionRef.current?.stop().catch(() => {});
    75→      sessionRef.current = null;
    76→      isReadyRef.current = false;
    77→    };
    78→  }, [clearQueue]);
    79→
    80→  const startSession = useCallback(async () => {
    81→    if (sessionRef.current) return;
    82→
    83→    console.log("[LiveAvatar] Fetching session token...");
    84→    const token = await fetchSessionToken();
    85→    console.log("[LiveAvatar] Token received, creating session...");
    86→    const session = new LiveAvatarSession(token);
    87→    sessionRef.current = session;
    88→
    89→    session.on(SessionEvent.SESSION_STREAM_READY, () => {
    90→      console.log("[LiveAvatar] Stream ready — attaching video + draining queue");
    91→      if (avatarRef.current) {
    92→        session.attach(avatarRef.current);
    93→      }
    94→      isReadyRef.current = true;
    95→      setIsReady(true);
    96→      // Drain any speech that queued while we were connecting
    97→      processQueue();
    98→    });
    99→
   100→    session.on(AgentEventsEnum.AVATAR_SPEAK_STARTED, () => {
   101→      console.log("[LiveAvatar] Avatar started speaking");
   102→      setIsSpeaking(true);
   103→    });
   104→
   105→    session.on(AgentEventsEnum.AVATAR_SPEAK_ENDED, () => {
   106→      console.log("[LiveAvatar] Avatar stopped speaking, processing next in queue");
   107→      isProcessingQueueRef.current = false;
   108→      processQueue();
   109→    });
   110→
   111→    session.on(SessionEvent.SESSION_DISCONNECTED, (reason) => {
   112→      console.log("[LiveAvatar] Disconnected:", reason);
   113→      isReadyRef.current = false;
   114→      setIsReady(false);
   115→      setIsSpeaking(false);
   116→      clearQueue();
   117→      sessionRef.current = null;
   118→    });
   119→
   120→    console.log("[LiveAvatar] Starting session...");
   121→    await session.start();
   122→    console.log("[LiveAvatar] session.start() resolved");
   123→  }, [processQueue, clearQueue]);
   124→
   125→  const stopSession = useCallback(async () => {
   126→    if (!sessionRef.current) return;
   127→    clearQueue();
   128→    isReadyRef.current = false;
   129→    await sessionRef.current.stop();
   130→    sessionRef.current = null;
   131→    setIsReady(false);
   132→    setIsSpeaking(false);
   133→  }, [clearQueue]);
   134→
   135→  const speak = useCallback(
   136→    (text: string) => {
   137→      if (!text.trim()) return;
   138→      console.log("[LiveAvatar] Queued:", text.slice(0, 60), `(ready=${isReadyRef.current}, queue=${speechQueueRef.current.length})`);
   139→      speechQueueRef.current.push(text);
   140→      setIsSpeaking(true);
   141→      processQueue();
   142→    },
   143→    [processQueue],
   144→  );
   145→
   146→  const interrupt = useCallback(() => {
   147→    if (!sessionRef.current) return;
   148→    clearQueue();
   149→    sessionRef.current.interrupt();
   150→  }, [clearQueue]);
   151→
   152→  return {
   153→    isReady,
   154→    isSpeaking,
   155→    startSession,
   156→    stopSession,
   157→    speak,
   158→    interrupt,
   159→    clearQueue,
   160→    avatarRef,
   161→  };
   162→}
